// Backup generates a json file from a slice of all ThreejsDB instances in the backrepo
func (backRepoThreejs *BackRepoThreejsStruct) Backup(dirPath string) {

	filename := filepath.Join(dirPath, "ThreejsDB.json")

	// organize the map into an array with increasing IDs, in order to have repoductible
	// backup file
	forBackup := make([]*ThreejsDB, 0)
	for _, threejsDB := range backRepoThreejs.Map_ThreejsDBID_ThreejsDB {
		forBackup = append(forBackup, threejsDB)
	}

	sort.Slice(forBackup[:], func(i, j int) bool {
		return forBackup[i].ID < forBackup[j].ID
	})

	file, err := json.MarshalIndent(forBackup, "", " ")

	if err != nil {
		log.Fatal("Cannot json Threejs ", filename, " ", err.Error())
	}

	err = ioutil.WriteFile(filename, file, 0644)
	if err != nil {
		log.Fatal("Cannot write the json Threejs file", err.Error())
	}
}

